-- ═══════════════════════════════════════════════════════════════════════════
-- CONSTITUTIONAL AMENDMENTS — 13th and 15th
-- ═══════════════════════════════════════════════════════════════════════════

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_040', 'ADVOCIS', 'CONSTITUTIONAL', 'US', 'U.S. Const. amend. XIII', '13th Amendment', 'Thirteenth Amendment — Abolition of Slavery and Involuntary Servitude', 'Abolishes slavery and involuntary servitude except as punishment for a crime. Grants Congress enforcement power.', '["Slavery and involuntary servitude abolished","Exception only for punishment upon conviction","Congress has power to enforce by appropriate legislation","Basis for 42 USC §§ 1981-1982","Applies to private actors — not limited to state action"]', '[{"section":"Section 1","description":"Neither slavery nor involuntary servitude shall exist within the United States"},{"section":"Section 2","description":"Congress shall have power to enforce this article by appropriate legislation"}]', '["1983_complaint","civil_rights_complaint","federal_complaint","involuntary_servitude_claim"]', '["constitutional-and-civil-rights-audit"]', 'Federal Courts / DOJ', 1, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_041', 'ADVOCIS', 'CONSTITUTIONAL', 'US', 'U.S. Const. amend. XV', '15th Amendment', 'Fifteenth Amendment — Voting Rights Regardless of Race', 'Prohibits federal and state governments from denying the right to vote based on race, color, or previous condition of servitude.', '["Right to vote cannot be denied on account of race, color, or previous condition of servitude","Applies to federal and state governments","Congress has enforcement power","Foundation for Voting Rights Act of 1965"]', '[{"section":"Section 1","description":"Right to vote not denied or abridged on account of race, color, or previous condition of servitude"},{"section":"Section 2","description":"Congress shall have power to enforce this article by appropriate legislation"}]', '["voting_rights_complaint","election_challenge","civil_rights_complaint","federal_complaint"]', '["constitutional-and-civil-rights-audit"]', 'Federal Courts / DOJ', 1, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- FEDERAL CIVIL RIGHTS STATUTES
