INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_042', 'ADVOCIS', 'FEDERAL_STATUTE', 'US', '42 USC § 1981', '§ 1981', 'Equal Rights Under the Law — Contracts and Property', 'All persons have the same right to make and enforce contracts, sue, give evidence, and enjoy full and equal benefit of all laws regardless of race.', '["Equal right to make and enforce contracts","Equal right to sue, be parties, give evidence","Full and equal benefit of all laws","Applies to private and public actors","No state action requirement — reaches private discrimination"]', '[{"section":"1981(a)","description":"Equal rights to make and enforce contracts"},{"section":"1981(b)","description":"Make and enforce contracts includes making, performance, modification, and termination"},{"section":"1981(c)","description":"Protection against nongovernmental discrimination"}]', '["employment_discrimination","contract_dispute","civil_rights_complaint","1981_claim"]', '["constitutional-and-civil-rights-audit"]', 'Federal Courts', 1, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_043', 'ADVOCIS', 'FEDERAL_STATUTE', 'US', '42 USC § 1982', '§ 1982', 'Property Rights of Citizens — Race Discrimination', 'All citizens have the same right to inherit, purchase, lease, sell, hold, and convey real and personal property regardless of race.', '["Equal property rights for all citizens","Prohibits racial discrimination in property transactions","Applies to private actors — no state action required","Derived from 13th Amendment enforcement power","Covers real and personal property"]', '[{"section":"§ 1982","description":"All citizens shall have the same right to inherit, purchase, lease, sell, hold, and convey real and personal property"}]', '["property_discrimination","housing_complaint","civil_rights_complaint","1982_claim"]', '["constitutional-and-civil-rights-audit"]', 'Federal Courts', 1, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_044', 'ADVOCIS', 'FEDERAL_STATUTE', 'US', '42 USC § 1988', '§ 1988', 'Attorney Fees in Civil Rights Cases', 'Authorizes courts to award reasonable attorney fees to prevailing parties in civil rights actions under §§ 1981-1983, 1985-1986, and Title VI/IX.', '["Prevailing plaintiff: fees awarded as a matter of course","Prevailing defendant: fees only if action frivolous, unreasonable, or without foundation","Reasonable hourly rate × reasonable hours","Applies to §§ 1981, 1982, 1983, 1985, 1986","Includes expert witness fees in some circuits"]', '[{"section":"1988(b)","description":"Court may allow prevailing party reasonable attorney fee as part of costs"},{"section":"1988(c)","description":"Expert fees in certain actions"}]', '["fee_petition","civil_rights_complaint","1983_complaint","prevailing_party_motion"]', '["constitutional-and-civil-rights-audit"]', 'Federal Courts', 1, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_045', 'ADVOCIS', 'FEDERAL_STATUTE', 'US', '42 USC §§ 2000a-2000a-6 (Title II, Civil Rights Act of 1964)', 'Title II', 'Public Accommodations — Civil Rights Act of 1964', 'Prohibits discrimination based on race, color, religion, or national origin in places of public accommodation affecting interstate commerce.', '["No discrimination in hotels, restaurants, theaters, gas stations","Applies to establishments affecting interstate commerce","Injunctive relief available","Attorney General may intervene","No damages — injunctive relief only"]', '[{"section":"2000a","description":"Prohibition against discrimination in public accommodations"},{"section":"2000a-2","description":"Injunctive relief against discrimination"},{"section":"2000a-3","description":"Civil actions for injunctive relief"},{"section":"2000a-5","description":"Attorney General may institute action"}]', '["public_accommodation_complaint","civil_rights_complaint","discrimination_claim","injunction_petition"]', '["constitutional-and-civil-rights-audit"]', 'Federal Courts / DOJ', 1, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_046', 'ADVOCIS', 'FEDERAL_STATUTE', 'US', '42 USC §§ 2000d-2000d-7 (Title VI, Civil Rights Act of 1964)', 'Title VI', 'Non-Discrimination in Federally Funded Programs', 'Prohibits discrimination on the basis of race, color, or national origin in any program or activity receiving federal financial assistance.', '["No discrimination on basis of race, color, or national origin","Applies to all programs receiving federal funds","Federal agencies must enforce through fund termination or other means","Private right of action for intentional discrimination","Disparate impact actionable under agency regulations"]', '[{"section":"2000d","description":"Prohibition against exclusion from federally assisted programs"},{"section":"2000d-1","description":"Federal authority may terminate funding for noncompliance"},{"section":"2000d-7","description":"Abrogation of state sovereign immunity"}]', '["Title_VI_complaint","federal_funding_challenge","discrimination_claim","agency_complaint"]', '["constitutional-and-civil-rights-audit"]', 'Federal Courts / Federal Agencies', 1, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_047', 'ADVOCIS', 'FEDERAL_STATUTE', 'US', '42 USC §§ 2000e-2000e-17 (Title VII, Civil Rights Act of 1964)', 'Title VII', 'Employment Discrimination — Civil Rights Act of 1964', 'Prohibits employment discrimination based on race, color, religion, sex, or national origin. Covers hiring, firing, compensation, and terms of employment.', '["Applies to employers with 15+ employees","Prohibits disparate treatment and disparate impact","EEOC charge required before suit (exhaustion)","180/300-day filing deadline","Remedies include back pay, reinstatement, compensatory and punitive damages"]', '[{"section":"2000e-2","description":"Unlawful employment practices"},{"section":"2000e-3","description":"Retaliation prohibited"},{"section":"2000e-5","description":"EEOC enforcement procedures and right to sue"},{"section":"2000e-16","description":"Federal employment nondiscrimination"}]', '["EEOC_charge","employment_discrimination","Title_VII_complaint","right_to_sue_letter"]', '["constitutional-and-civil-rights-audit"]', 'EEOC / Federal Courts', 1, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_048', 'ADVOCIS', 'FEDERAL_STATUTE', 'US', '42 USC §§ 12101-12213 (Americans with Disabilities Act)', 'ADA', 'Americans with Disabilities Act — Titles I through III', 'Prohibits discrimination against individuals with disabilities in employment, public services, and public accommodations.', '["Title I: Employment — employers with 15+ employees","Title II: Public services — state and local government","Title III: Public accommodations — private entities","Reasonable accommodation required","Interactive process for accommodations","Undue hardship defense available"]', '[{"section":"12112","description":"Title I — Employment discrimination prohibition"},{"section":"12132","description":"Title II — Public services discrimination prohibition"},{"section":"12182","description":"Title III — Public accommodations discrimination prohibition"},{"section":"12203","description":"Retaliation and coercion prohibited"}]', '["ADA_complaint","EEOC_charge","reasonable_accommodation","accessibility_complaint","DOJ_complaint"]', '["constitutional-and-civil-rights-audit"]', 'EEOC / DOJ / Federal Courts', 1, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_049', 'ADVOCIS', 'FEDERAL_STATUTE', 'US', '29 USC § 794 (Section 504, Rehabilitation Act of 1973)', 'Section 504', 'Rehabilitation Act — Disability Discrimination in Federally Funded Programs', 'Prohibits disability discrimination by any program or activity receiving federal financial assistance or conducted by a federal agency.', '["No exclusion from federally funded programs solely by reason of disability","Reasonable accommodations required","Applies to all federal agencies and recipients of federal funds","Predates ADA — broader federal coverage","Private right of action available"]', '[{"section":"794(a)","description":"No qualified individual with a disability shall be excluded from any program receiving federal assistance"},{"section":"794(b)","description":"Program or activity defined broadly"},{"section":"794a","description":"Remedies and attorney fees"}]', '["Section_504_complaint","disability_accommodation","federal_funding_complaint","civil_rights_complaint"]', '["constitutional-and-civil-rights-audit"]', 'Federal Agencies / Federal Courts', 1, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_050', 'ADVOCIS', 'FEDERAL_STATUTE', 'US', '34 USC §§ 12291+ (Violence Against Women Act)', 'VAWA', 'Violence Against Women Act', 'Comprehensive federal legislation addressing domestic violence, dating violence, sexual assault, and stalking with grant programs, protections, and enforcement provisions.', '["Full faith and credit for protection orders across states","Federal interstate domestic violence crimes","Grant programs for victim services","Housing protections for victims","Reauthorized multiple times (1994, 2000, 2005, 2013, 2022)"]', '[{"section":"12291","description":"Definitions and grant conditions"},{"section":"12361","description":"Research and reporting on violence against women"},{"section":"12421","description":"Legal assistance for victims"}]', '["VAWA_petition","protection_order","domestic_violence_complaint","victim_services","immigration_VAWA"]', '["constitutional-and-civil-rights-audit"]', 'DOJ / Federal Courts', 1, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_051', 'ADVOCIS', 'FEDERAL_STATUTE', 'US', '18 USC §§ 241-242', '§§ 241-242', 'Conspiracy Against Rights / Deprivation of Rights Under Color of Law', 'Federal criminal statutes prohibiting conspiracy to deprive civil rights (§ 241) and deprivation of rights under color of law (§ 242).', '["§ 241: Conspiracy of two or more persons to deprive any person of rights","§ 242: Willful deprivation of rights under color of law","Felony if bodily injury, attempt to kill, or death results","§ 241: Up to 10 years (life if death results)","§ 242: Up to 1 year (10 years if bodily injury; life if death results)"]', '[{"section":"241","description":"Conspiracy against rights — two or more persons conspire to injure, oppress, threaten, or intimidate"},{"section":"242","description":"Deprivation of rights under color of law — willful subjection to different punishments, pains, or penalties by reason of color or race"}]', '["federal_criminal_complaint","civil_rights_referral","DOJ_complaint","police_misconduct","1983_complaint"]', '["constitutional-and-civil-rights-audit","police-report-data-cross-reference"]', 'DOJ / FBI / Federal Courts', 0, 1, datetime('now'), datetime('now'));


