INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_052', 'ADVOCIS', 'CASE_LAW', 'US', 'Canton v. Harris (1989) 489 U.S. 378', 'Canton v. Harris', 'Failure to Train as Municipal Policy Under § 1983', 'A municipality may be liable under § 1983 for failure to train its employees where the failure amounts to deliberate indifference to constitutional rights.', '["Failure to train can be basis for Monell liability","Must show deliberate indifference to rights of persons","Need for training must be so obvious — known or obvious risk","Deficiency must be closely related to ultimate injury","Single incident can suffice if predictable and severe"]', '[{"section":"Holding","description":"Failure to train may constitute municipal policy if deliberate indifference shown"},{"section":"Standard","description":"Deliberate indifference — municipality knows training is inadequate and likely to cause violation"}]', '["1983_complaint","Monell_claim","failure_to_train","municipal_liability","police_misconduct"]', '["constitutional-and-civil-rights-audit","police-report-data-cross-reference"]', 'Federal Courts', 1, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_053', 'ADVOCIS', 'CASE_LAW', 'US', 'Mathews v. Eldridge (1976) 424 U.S. 319', 'Mathews v. Eldridge', 'Due Process Balancing Test', 'Three-part balancing test for determining what process is due before government deprivation of a protected interest.', '["Factor 1: Private interest affected by official action","Factor 2: Risk of erroneous deprivation through procedures used and probable value of additional safeguards","Factor 3: Government interest including fiscal and administrative burdens","Flexible standard — not one-size-fits-all","Applies to all government benefit and liberty deprivations"]', '[{"section":"Holding","description":"Due process requires balancing private interest, risk of error, and government interest"},{"section":"Three-Factor Test","description":"Balancing test determines what procedural protections are constitutionally required"}]', '["due_process_claim","benefits_appeal","administrative_hearing","1983_complaint","federal_complaint"]', '["constitutional-and-civil-rights-audit"]', 'Federal Courts', 1, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_054', 'ADVOCIS', 'CASE_LAW', 'US', 'Tennessee v. Garner (1985) 471 U.S. 1', 'Tennessee v. Garner', 'Deadly Force by Police — Fleeing Suspect', 'Deadly force to prevent escape of a fleeing suspect violates the Fourth Amendment unless the officer has probable cause to believe the suspect poses a significant threat of death or serious physical injury.', '["Deadly force is a seizure under the Fourth Amendment","Cannot use deadly force solely to prevent escape","Must have probable cause suspect poses significant threat of death or serious injury","Warning must be given where feasible","Applies to all law enforcement"]', '[{"section":"Holding","description":"Deadly force to prevent escape violates 4th Amendment unless suspect poses significant threat"},{"section":"Standard","description":"Probable cause that suspect poses threat of serious physical harm to officer or others"}]', '["use_of_force_report","officer_involved_shooting","1983_complaint","police_report","excessive_force_complaint"]', '["constitutional-and-civil-rights-audit","police-report-data-cross-reference"]', 'Federal Courts', 1, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_055', 'ADVOCIS', 'CASE_LAW', 'US', 'Mapp v. Ohio (1961) 367 U.S. 643', 'Mapp v. Ohio', 'Exclusionary Rule Applies to States', 'Evidence obtained through unreasonable searches and seizures in violation of the Fourth Amendment is inadmissible in state court proceedings through the Fourteenth Amendment.', '["Exclusionary rule applies to states via 14th Amendment","Evidence obtained in violation of 4th Amendment must be excluded","Fruit of the poisonous tree doctrine applies","Good faith exception recognized later in Leon","Applies to both physical evidence and statements"]', '[{"section":"Holding","description":"Exclusionary rule is incorporated against states through 14th Amendment due process"},{"section":"Remedy","description":"All evidence obtained by unconstitutional search and seizure is inadmissible in state court"}]', '["suppression_motion","search_warrant","4th_amendment_challenge","criminal_defense","police_report"]', '["constitutional-and-civil-rights-audit","police-report-data-cross-reference"]', 'Federal / State Courts', 1, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_056', 'ADVOCIS', 'CASE_LAW', 'US', 'Miranda v. Arizona (1966) 384 U.S. 436', 'Miranda v. Arizona', 'Custodial Interrogation Rights', 'Prior to custodial interrogation, a suspect must be informed of the right to remain silent, that statements may be used against them, and the right to an attorney.', '["Warnings required before custodial interrogation","Right to remain silent","Anything said can and will be used in court","Right to an attorney","If cannot afford attorney, one will be appointed","Waiver must be voluntary, knowing, and intelligent"]', '[{"section":"Holding","description":"5th Amendment requires warnings before custodial interrogation"},{"section":"Miranda Warnings","description":"Silence, use against, right to counsel, appointed counsel"},{"section":"Waiver","description":"Must be voluntary, knowing, and intelligent"}]', '["Miranda_warning","custodial_interrogation","suppression_motion","confession","police_report"]', '["constitutional-and-civil-rights-audit","police-report-data-cross-reference"]', 'Federal / State Courts', 1, 1, datetime('now'), datetime('now'));


