INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_057', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Gov. Code §§ 12900-12996 (FEHA Employment Provisions)', 'FEHA Employment', 'Fair Employment and Housing Act — Employment Provisions', 'California law prohibiting employment discrimination based on race, religion, color, national origin, ancestry, physical disability, mental disability, medical condition, genetic information, marital status, sex, gender, sexual orientation, age, or military/veteran status.', '["Applies to employers with 5+ employees (harassment: 1+)","Broader protected classes than Title VII","DFEH/CRD complaint required before suit (exhaustion)","1-year statute of limitations for CRD complaint","Remedies include unlimited compensatory damages, punitive damages, injunctive relief"]', '[{"section":"12940","description":"Unlawful employment practices — discrimination, harassment, retaliation"},{"section":"12940(j)","description":"Employer liability for harassment"},{"section":"12940(k)","description":"Failure to prevent discrimination and harassment"},{"section":"12965","description":"Civil actions and right to sue"}]', '["DFEH_complaint","CRD_complaint","employment_discrimination","harassment_complaint","right_to_sue"]', '["constitutional-and-civil-rights-audit"]', 'CA Civil Rights Department / California Courts', 1, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_058', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code § 149', 'PC § 149', 'Assault Under Color of Authority', 'Every public officer who, under color of authority and without lawful necessity, assaults or beats any person is guilty of a felony.', '["Applies to all public officers","Assault or battery under color of authority","Without lawful necessity","Felony offense","Covers law enforcement, correctional officers, and other public officials"]', '[{"section":"§ 149","description":"Public officer assault under color of authority — felony punishable by imprisonment in state prison"}]', '["criminal_complaint","police_misconduct","excessive_force","internal_affairs","1983_complaint"]', '["constitutional-and-civil-rights-audit","police-report-data-cross-reference"]', 'California DA / AG', 1, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_059', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Gov. Code § 815.2', 'Gov. Code § 815.2', 'Public Entity Vicarious Liability', 'A public entity is liable for injury proximately caused by an act or omission of an employee within the scope of employment if the act or omission would give rise to a cause of action against the employee.', '["Public entity liable for employee acts within scope of employment","Employee must have individual liability","Scope of employment determined by respondeat superior principles","Not liable if employee immune from liability","Foundation for suing government agencies for employee misconduct"]', '[{"section":"815.2(a)","description":"Public entity liable for injury caused by employee act or omission within scope of employment"},{"section":"815.2(b)","description":"Not liable if employee is immune"}]', '["government_tort_claim","police_misconduct","1983_complaint","vicarious_liability","state_court_complaint"]', '["constitutional-and-civil-rights-audit","police-report-data-cross-reference"]', 'California Courts', 1, 1, datetime('now'), datetime('now'));
